"""
MKT Christ Layer — Jeremiah chapters 22–24
Run: python3 scripts/zc-christ-jeremiah-22-24-fill.py

Ch 22: Royal accountability oracles — culminating in the Coniah throne-curse.
Ch 23: False shepherds → Good Shepherd promise → Righteous Branch → false prophets.
Ch 24: Two baskets of figs — the good-exile promise with the proto-new-covenant.

Key Christological pivots:
- 22:16: 'Defending the poor = knowing me' — Jesus's Matt 25:31-46 identification
  of himself with 'the least of these' is the NT enactment of this verse.
- 22:24-30: Coniah/Jehoiachin curse ('childless, throne-stripped') — resolved by
  the virgin birth: Matthew's genealogy passes through Jehoiachin legally (Joseph's
  line), but Jesus is not biologically descended from him — bypassing the curse while
  maintaining Davidic lineage.
- 23:5-6: Tzemach Tzaddiq / YHWH Tsidqenu — the messianic Branch who is 'the LORD
  our Righteousness'; Paul's 2 Cor 5:21 / 1 Cor 1:30 are the NT fulfillment.
- 23:1-4: Woe to false shepherds → Jesus the Good Shepherd (John 10:11-14).
- 23:18, 23-24: Standing in the divine council / God fills heaven and earth —
  Jesus's unique intimacy with the Father (John 5:19-20; 17:24-26).
- 24:7: 'Heart to know me' — proto-new-covenant; fulfilled through the Spirit Christ
  gives (John 7:37-39; Ezek 36:26-27).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JER_CHRIST = {
  "22": {
    "1": "<p>YHWH sends Jeremiah to the royal palace to deliver a word directly to the king. Jesus likewise takes his message to the center of religious authority — the temple and the ruling establishment. The prophetic pattern: YHWH&apos;s word goes to the seat of power, and the messenger is sent not merely to comfort but to confront. Jesus&apos;s entry into Jerusalem and the temple (Matt 21:10-17) enacts this pattern as its culmination.</p>",
    "2": "<p>The address to the king sitting on David&apos;s throne. Jesus is the Davidic king who sits on the ultimate throne: &apos;The Lord God will give him the throne of his father David, and he will reign over Jacob&apos;s descendants forever; his kingdom will never end&apos; (Luke 1:32-33). Every oracle addressed to the Davidic throne points toward the one in whom that throne is finally and permanently occupied.</p>",
    "3": "<p>&apos;Do what is just and right. Rescue those who have been robbed. Do not mistreat the foreigner, the fatherless, or the widow.&apos; The justice-command that defines Davidic kingship. Jesus embodies this: &apos;The Spirit of the Lord is on me, because he has anointed me to proclaim good news to the poor... to set the oppressed free&apos; (Luke 4:18-19 citing Isa 61:1-2). His first sermon is a justice manifesto fulfilling the Davidic covenant requirement.</p>",
    "4": "<p>Conditional promise: if the king obeys, Davidic kings will continue to enter through the gates. Jesus fulfills the condition perfectly — he is the obedient Davidic king who passes through the gates of Jerusalem in his triumphal entry (Matt 21:9: &apos;Hosanna to the Son of David!&apos;) and through the gates of the heavenly city in his ascension (Ps 24:7-10: &apos;Lift up your heads, O gates... that the King of glory may come in&apos;).</p>",
    "5": "<p>&apos;I swear by myself that this house will become a ruin.&apos; The divine self-oath — the ultimate guarantee. Jesus speaks with the same absolute authority without requiring an oath: &apos;Truly, truly I say to you&apos; (the &apos;Amen, amen&apos; formula of John&apos;s Gospel) places his word on par with the divine self-oath. James 5:12 (echoing Matt 5:37) grounds this in Jesus&apos;s teaching: let your yes be yes, no oath required — because his word is as reliable as YHWH&apos;s own oath.</p>",
    "6": "<p>The palace compared to Gilead and Lebanon — prized, beautiful, but destined for desolation. Jesus uses cedar imagery for the contrast between the elaborate and the genuine: &apos;look at the birds of the air... your heavenly Father feeds them&apos; (Matt 6:26); &apos;consider the lilies... not even Solomon in all his glory was dressed like one of these&apos; (Matt 6:29). The palace&apos;s magnificent cedars will become a ruin; the kingdom of heaven outlasts all cedar palaces.</p>",
    "7": "<p>Destroyers sent against the finest cedar trees — judgment that attacks the specific symbol of royal pride. The destroying agents in the NT are identified: the Romans in 70 CE fulfill this, as Jesus predicted (Matt 24:2: &apos;not one stone will be left on another&apos;). The temple and palace destruction of 70 CE is Jeremiah&apos;s oracle reaching its NT fulfillment through Jesus&apos;s announcement.</p>",
    "8": "<p>&apos;Why has the LORD done this to such a great city?&apos; — the nations&apos; question at Jerusalem&apos;s fall. Jesus anticipates that his own disciples will ask the same question about the coming judgment and answers it in the Olivet Discourse (Matt 24). The &apos;why&apos; question has a consistent answer: the rejection of YHWH&apos;s covenant, here climaxed in the rejection of YHWH&apos;s Son.</p>",
    "9": "<p>The answer: they abandoned the covenant and served other gods. Jesus in John 5:39-40 diagnoses his contemporaries: &apos;You study the Scriptures diligently because you think that in them you have eternal life... yet you refuse to come to me to have life.&apos; The abandonment of covenant relationship for religious form is the same sin — now rejecting the covenant-maker who has come in person.</p>",
    "10": "<p>&apos;Do not weep for the dead king; weep for the one who goes into exile, for he will never see this land again.&apos; The one who goes into exile loses more than the one who dies — death ends suffering; exile continues it. Jesus&apos;s blessing &apos;blessed are those who mourn, for they will be comforted&apos; (Matt 5:4) reverses this: grief and exile under Christ&apos;s kingdom are temporary. The permanent exile of 22:10 is reversed by the permanent homecoming Christ promises (John 14:3).</p>",
    "11": "<p>Shallum/Jehoahaz — taken captive to Egypt after three months of reign (2 Kgs 23:31-34). His brief reign and permanent exile is a foil for Jesus&apos;s brief earthly ministry that leads to permanent enthronement. Where the Davidic king is exiled never to return, the Son of David goes away (via cross and resurrection) and returns — and his return is permanent (Heb 7:24: &apos;because Jesus lives forever, he has a permanent priesthood&apos;).</p>",
    "12": "<p>&apos;He will die in the place he has been taken captive, and will never see this land again.&apos; The death in exile of an unfaithful king. Jesus, by contrast, dies in the land — the specific death in the specific place that fulfills covenant prophecy (Ps 22; Isa 53; Zech 12:10). His death is not exile but the definitive act within the covenant land that achieves what no exile could: atonement for all the unfaithful kings and people he represents.</p>",
    "13": "<p>&apos;Woe to him who builds his palace through injustice ... who makes his countrymen work for nothing, not paying them for their labor.&apos; The woe against Jehoiakim&apos;s exploitative building projects. Jesus pronounces seven woes against the scribes and Pharisees (Matt 23:13-36) using the same prophetic form — woe-oracles against religious leaders who exploit those under their care. The form Jeremiah uses against the king Jesus uses against the religious establishment.</p>",
    "14": "<p>The grand palace with large rooms, cedar paneling, vermilion paint — conspicuous consumption as royal validation. Jesus&apos;s contrast: &apos;foxes have dens and birds have nests, but the Son of Man has no place to lay his head&apos; (Matt 8:20; Luke 9:58). The one who is more than any Davidic king rejects the cedar-palace model entirely. His kingdom is not built by exploited labor but by self-giving service.</p>",
    "15": "<p>&apos;Does building a rival in cedar prove you are a king? Your father ate and drank, and it went well — he administered justice and righteousness and it went well.&apos; Josiah as the model king: the one who administered justice flourished; the one who built cedar proved nothing. Jesus&apos;s teaching: &apos;whoever wants to be great among you must be your servant... just as the Son of Man did not come to be served but to serve&apos; (Matt 20:26-28). Greatness through service rather than through construction or consumption.</p>",
    "16": "<p>&apos;He defended the cause of the poor and needy — is that not what it means to know me?&apos; declares the LORD. The knowledge of God expressed in justice for the poor: <em>da-at YHWH</em> = care for the vulnerable. Jesus&apos;s Matt 25:31-46 enacts this with revolutionary force: &apos;whatever you did for one of the least of these brothers and sisters of mine, you did for me.&apos; Meeting Jesus in the poor is meeting YHWH — the same identification that 22:16 makes between knowing YHWH and defending the poor.</p>",
    "17": "<p>&apos;But you have no eyes or heart for anything except your own dishonest gain, and for shedding innocent blood.&apos; Jehoiakim&apos;s moral blindness — eyes and heart fixed on profit and violence. Jesus: &apos;blessed are the pure in heart, for they will see God&apos; (Matt 5:8) — purity of heart (the opposite of Jehoiakim&apos;s divided, greedy heart) is the condition for seeing YHWH. His own pure heart, set entirely on the Father&apos;s will, makes him the only one who sees God clearly (John 1:18).</p>",
    "18": "<p>Jehoiakim&apos;s shameless death — no mourning. The contrast with Jesus&apos;s death is complete: the women wept (Luke 23:27-28), Joseph of Arimathea took care for proper burial (John 19:38-42), the earth shook and rocks split (Matt 27:51-54). Even creation mourned at the cross in a way no one mourned for Jehoiakim. The death of the just receives the honor the unjust king is denied.</p>",
    "19": "<p>&apos;He will be buried like a donkey — dragged away and thrown outside the gates of Jerusalem.&apos; The undignified death and disposal of Jehoiakim. Jesus was crucified outside the city gate (Heb 13:12: &apos;Jesus suffered outside the city gate to make the people holy through his own blood&apos;) — in the place of the cursed and disgraced. But his burial was honorable (Isa 53:9: &apos;he was assigned a grave with the wicked, and with the rich in his death&apos;), and his resurrection is the ultimate reversal of the Jehoiakim-pattern.</p>",
    "20": "<p>The cry to Lebanon, Bashan, and Abarim — all allies crushed, all lovers taken. The collapse of the political alliances that replaced trust in YHWH. Jesus&apos;s disciples will similarly scatter when he is arrested (Matt 26:56: &apos;then all the disciples deserted him and fled&apos;) — the allies failing in the moment of crisis. But his resurrection reconstitutes the community on a different basis than political alliance: it is covenant loyalty, not geopolitical calculation, that holds.</p>",
    "21": "<p>&apos;I warned you when you were at ease, but you said: I will not listen. This has been your habit from your youth.&apos; The lifelong pattern of not listening. Heb 3:7-11 cites Ps 95:7-11 for the same warning: &apos;today if you hear his voice, do not harden your hearts&apos;. The history of not-listening culminates in the rejection of the Son (John 1:11: &apos;he came to his own, and his own did not receive him&apos;). The pattern of the wilderness generation, Jeremiah&apos;s generation, and Jesus&apos;s generation are the same.</p>",
    "22": "<p>The wind sweeping away rulers; allies taken captive — the comprehensive collapse of Jerusalem&apos;s power structure. Jesus&apos;s kingdom is established through the opposite of political power: &apos;my kingdom is not of this world; if it were, my servants would fight&apos; (John 18:36). The wind of judgment that sweeps away earthly rulers cannot touch his kingdom, because it was never constituted by those structures.</p>",
    "23": "<p>&apos;You who live in Lebanon, nestled among the cedars — how you will groan when birth pangs seize you!&apos; The image of birth pangs (<em>chil ke-yoleda</em>) for judgment. Jesus uses the birth-pang image for the eschaton: &apos;all these are the beginning of birth pangs&apos; (Matt 24:8; Mark 13:8) — the suffering of the end-time is the labor that precedes new creation. Paul: &apos;we know that the whole creation has been groaning as in the pains of childbirth right up to the present time&apos; (Rom 8:22). The cedar-nestled pride of Jerusalem groans in judgment; creation groans in hope.</p>",
    "24": "<p>&apos;Even if Coniah ... were the signet ring on my right hand, I would still pull you off.&apos; The signet ring (<em>hotam</em>) was the instrument of royal authority — the king&apos;s personal seal pressed into official documents. YHWH pulls the signet off Coniah: the authority is withdrawn. This is the background for Hag 2:23 where YHWH restores the signet to Zerubbabel (a descendant of Jehoiachin): &apos;I will make you like my signet ring, for I have chosen you.&apos; The removed signet will be restored — but only through the Zerubbabel line that leads to Jesus.</p>",
    "25": "<p>Hand Coniah over to Nebuchadnezzar — the king being handed into the enemy&apos;s power. Jesus was &apos;handed over&apos; (<em>paredideto</em>) to the authorities (Matt 26:2, 45; 27:2, 18) — the same covenantal surrender. But while Coniah&apos;s hand-over is judgment, Jesus&apos;s hand-over is redemptive: &apos;he was delivered over to death for our sins and was raised to life for our justification&apos; (Rom 4:25).</p>",
    "26": "<p>&apos;I will hurl you and the mother who bore you into another country, a land where neither of you was born, and there you will die.&apos; The exile of the king and queen mother (Nehushta). The queen mother (<em>gevirah</em>) held significant status in the Davidic court (1 Kgs 2:19; 15:13; 2 Kgs 10:13). Mary, Jesus&apos;s mother, is present at both the beginning and end of his ministry — at the wedding of Cana (John 2:1-5) and at the cross (John 19:25-27). Unlike Nehushta who is hurled into exile with her son, Mary is given a home by the beloved disciple (John 19:27).</p>",
    "27": "<p>&apos;They will never return&apos; — the permanent exile of Coniah and his mother. Jehoiachin historically remained in Babylon until his release in his old age (2 Kgs 25:27-30; the Babylonian Chronicles mention him receiving rations from Nebuchadnezzar). He died in exile. The throne-promise is fulfilled not by Jehoiachin&apos;s return but by his descendant (through Zerubbabel) Jesus of Nazareth — who establishes the Davidic kingdom without geographic land-return, because his kingdom transcends territory.</p>",
    "28": "<p>&apos;Is this man Coniah nothing but a broken, despised clay pot — something no one wants?&apos; The lament over the deposed king as broken pottery. Isa 53:3 describes the Suffering Servant: &apos;he was despised and rejected by mankind, a man of suffering and familiar with pain ... he was despised, and we held him in low esteem.&apos; Jesus the descendent of Coniah inherits both the throne-promise and the throne-curse — but in his case the despising and rejection become the means of redemption.</p>",
    "29": "<p><em>Eretz eretz eretz shim-i dvar YHWH</em>: O land, land, land, hear the word of the LORD! — the unprecedented triple call, more urgent than the prophetic double-call. The triple invocation has eschatological weight: the land itself must hear what is happening to the Davidic covenant. The NT makes the land a universal concept: &apos;the meek will inherit the earth/<em>gē</em>&apos; (Matt 5:5) — the land-promise of the covenant expands to the new earth (Rev 21:1-4). The triple call of earth-land-earth is answered by the eschatological new creation.</p>",
    "30": "<p>&apos;Record this man as though childless — no one from his descendants will succeed in sitting on David&apos;s throne.&apos; The Coniah decree: throne-stripped, functionally childless for Davidic purposes. Matthew&apos;s genealogy (Matt 1:12) includes Jeconiah (Coniah) in the legal line of Joseph — but Jesus is not biologically Joseph&apos;s son (Matt 1:18-25; Luke 1:34-35). He is Joseph&apos;s legal heir (inheriting the Davidic claim) but not Joseph&apos;s biological heir (not biologically descended from Coniah). The virgin birth is the theological key: it simultaneously maintains the Davidic lineage through Joseph and bypasses the biological throne-curse. Jesus is the Davidic heir through whom no descendant of Coniah biologically sits on the throne — exactly fulfilling the decree while also fulfilling the promise.</p>"
  },
  "23": {
    "1": "<p>&apos;Woe to the shepherds who destroy and scatter the sheep of my pasture!&apos; The woe-oracle against the false shepherds opens the chapter that ends with the Righteous Branch. Jesus is the Good Shepherd (John 10:11-14) who stands in contrast to every false shepherd in Israel&apos;s history. His self-identification as the good shepherd takes up the entire language of Jeremiah 23: he knows his sheep, they know him, he lays down his life for them rather than scattering and destroying them.</p>",
    "2": "<p>The shepherds have scattered YHWH&apos;s flock and driven them away — YHWH will punish them for it. Jesus identifies himself as the one YHWH sends in fulfillment of this promise of punishment and replacement. In the Parable of the Tenants (Matt 21:33-46) the wicked tenants-shepherds are removed and the vineyard given to others. The punishment of the false shepherds is YHWH&apos;s vindication of the flock.</p>",
    "3": "<p>&apos;I myself will gather the remnant of my flock from all the lands where I have driven them.&apos; YHWH as the gathering shepherd. Jesus: &apos;I have other sheep that are not of this sheep pen; I must bring them also&apos; (John 10:16). His gathering work extends beyond ethnic Israel to the nations — the global gathering that &apos;all the lands&apos; implies. Matt 28:19-20: the Great Commission is the mechanism by which YHWH gathers the global remnant through the Son&apos;s sent messengers.</p>",
    "4": "<p>&apos;I will raise up shepherds who will truly care for them; they will no longer be afraid or terrified, and none will be missing.&apos; The promise of faithful under-shepherds. Jesus fulfills the &apos;none missing&apos; (literally: &apos;they shall not be lacking&apos;) guarantee: &apos;of all those he has given me I will lose none, but raise them up at the last day&apos; (John 6:39); &apos;I give them eternal life, and they shall never perish; no one will snatch them out of my hand&apos; (John 10:28). The &apos;none missing&apos; of v. 4 is the &apos;lose none&apos; of John 6:39.</p>",
    "5": "<p><strong>The Righteous Branch Oracle: <em>hineh yamim baim neum YHWH vahaqimoti leDavid tzemach tzaddiq</em></strong>: Behold, the days are coming when I will raise up for David a righteous Branch who will reign wisely and do what is just and right in the land. This is the central messianic promise of Jeremiah. <em>Tzemach</em> (Branch/Shoot) is a technical messianic title: it appears again at Jer 33:15, Zech 3:8 (&apos;my servant the Branch&apos;), and Zech 6:12 (&apos;the man whose name is the Branch, and he will branch out from his place and build the temple of the LORD&apos;). The Branch reigns wisely (<em>vesakhal</em>), does justice and righteousness (<em>mishpat utzedaqah</em>) — the defining characteristics of the ideal Davidic king (Isa 9:7; 11:1-5). Jesus fulfills every element: Davidic descent (Luke 1:27, 32-33; Matt 1:1), wisdom (Luke 2:52; Matt 12:42), justice (Matt 12:18-21 citing Isa 42:1-4), and righteousness (Heb 7:26).</p>",
    "6": "<p><strong><em>YHWH Tsidqenu</em></strong>: &apos;This is the name by which he will be called: The LORD our Righteousness.&apos; The divine name given to the messianic king is itself a form of YHWH&apos;s name — the Branch is identified as YHWH present. This is one of the most explicit OT identifications of the messianic king with YHWH himself. Paul applies this directly to Christ: &apos;Christ Jesus... has become for us wisdom from God — that is, our righteousness, holiness and redemption&apos; (1 Cor 1:30); &apos;God made him who had no sin to be sin for us, so that in him we might become the righteousness of God&apos; (2 Cor 5:21). Jesus is YHWH Tsidqenu — the LORD who becomes our righteousness.</p>",
    "7": "<p>The new Exodus that will supersede the old: &apos;no longer will they say, As the LORD lives who brought Israel up from Egypt.&apos; The greater deliverance will make the first deliverance seem secondary by comparison. Jesus inaugurates this new Exodus: Matt 2:15 (&apos;Out of Egypt I called my son&apos;) identifies Jesus as the true Israel making the definitive Exodus; the transfiguration has Moses and Elijah speaking about his &apos;departure&apos; (<em>exodon</em>, Luke 9:31) — his death-and-resurrection is the new Exodus; the Last Supper reframes Passover around his own body and blood as the new Exodus meal (Luke 22:14-20).</p>",
    "8": "<p>&apos;As the LORD lives who brought up the descendants of Israel from the north country and from all the lands where he had driven them.&apos; The new Exodus includes the diaspora from all directions — a global gathering. Acts 2:5-11 shows this beginning at Pentecost: Jews &apos;from every nation under heaven&apos; hear the gospel. The gathering from north and south and all the lands is the Spirit-enabled gathering of the new covenant era.</p>",
    "9": "<p>Jeremiah&apos;s anguish at the prophets&apos; corruption — his heart broken, his bones trembling, like a drunken man overcome by YHWH&apos;s holy words. This prophetic agony participates in the divine grief. Jesus&apos;s agony in Gethsemane (Luke 22:44: &apos;being in anguish, he prayed more earnestly&apos;) is the Son bearing the same weight of the holy word of judgment — but taking it into himself rather than pronouncing it outward.</p>",
    "10": "<p>Land full of adulterers; curse making the land mourn; the wilderness pastures dried up. The cosmic consequences of moral corruption: the land itself responds to human faithlessness (Rom 8:19-22). Jesus&apos;s death and resurrection begins the reversal: the creation that was subjected to futility will be liberated (Rom 8:21). His resurrection-presence transforms the barren (John 15:5: &apos;apart from me you can do nothing&apos;; &apos;with me you bear much fruit&apos;).</p>",
    "11": "<p>&apos;Both prophet and priest are godless; even in my own house I have found their wickedness.&apos; The corruption at the center — the sacred professions have been profaned. Jesus drives out the merchants from the temple (Matt 21:12-13) precisely because the house of prayer has been corrupted by those who should have been its guardians. His action enacts this oracle&apos;s judgment in real time.</p>",
    "12": "<p>Slippery paths in darkness for the false prophets — they will be driven into darkness and fall. Jesus&apos;s &apos;I am the light of the world&apos; (John 8:12; 9:5) is the answer to the darkness in which the false prophets stumble. Those who follow him &apos;will never walk in darkness but will have the light of life.&apos; The slippery path in the dark is the condition of those who reject the true shepherd-prophet.</p>",
    "13": "<p>Prophets of Samaria prophesying by Baal, leading Israel astray. The northern kingdom&apos;s false prophecy as the precursor to Jerusalem&apos;s worse version (v. 14). Jesus&apos;s warning about false prophets (Matt 7:15-23; 24:11, 24) anticipates the NT pattern. The test of the true prophet: &apos;by their fruit you will recognize them&apos; (Matt 7:20) — not the claims made but the direction they lead the flock (toward or away from the true shepherd).</p>",
    "14": "<p>&apos;In the prophets of Jerusalem I have seen something even more horrible: they commit adultery and live by lies.&apos; Greater privilege means greater accountability. Jesus&apos;s woes against Chorazin and Bethsaida (Matt 11:21-22): &apos;it will be more bearable for Tyre and Sidon on the day of judgment than for you&apos; — those who received the most (miracles in the presence of Jesus) and rejected it bear greater judgment.</p>",
    "15": "<p>Wormwood and poisoned water for the false prophets. The bitter cup they cause others to drink returns to them. Jesus takes the bitter cup that judgment requires (Mark 14:36: &apos;take this cup from me — yet not what I will, but what you will&apos;). His willingness to drink the cup of judgment means that those who trust in him are not given the wormwood-and-gall that the false prophets prescribed as safe.</p>",
    "16": "<p>&apos;Do not listen to the prophets who are prophesying to you; they are filling you with false hopes.&apos; The prophets who speak from their own hearts (<em>machzon libbam</em>). Jesus&apos;s teaching comes from the Father, not from his own heart in isolation: &apos;my teaching is not my own; it comes from the one who sent me&apos; (John 7:16); &apos;the words I say to you I do not speak on my own authority; the Father, living in me, is doing his work&apos; (John 14:10). The criterion for distinguishing true from false prophecy is whether it originates in the divine council or the prophet&apos;s own imagination.</p>",
    "17": "<p>&apos;They keep telling those who follow stubbornness of heart: No disaster will come.&apos; The false peace — confirming the stubborn in their stubbornness. Jesus refuses this comfort: &apos;do not think I came to bring peace to the earth; I did not come to bring peace, but a sword&apos; (Matt 10:34). The sword that divides is more merciful than the false peace that confirms people in paths that end in judgment.</p>",
    "18": "<p>&apos;For which of them has stood in the LORD&apos;s council to see and hear his word?&apos; The <em>sod YHWH</em> (divine council) — the criterion for authentic prophecy. Jesus has unique, permanent standing in the Father&apos;s council: &apos;the Son can do nothing by himself; he can do only what he sees his Father doing, because whatever the Father does the Son also does&apos; (John 5:19); &apos;I have made known to you everything I heard from my Father&apos; (John 15:15). He is the prophet who has fully stood in YHWH&apos;s council and speaks from complete divine intimacy.</p>",
    "19": "<p>The storm of YHWH, his wrath going out like a whirling tempest, falling on the heads of the wicked. The divine-warrior storm that no false prophet can prevent. Jesus stills the storm (Matt 8:23-27; Mark 4:35-41; Luke 8:22-25) — &apos;who is this? Even the wind and the waves obey him!&apos; — demonstrating that he is YHWH the storm-commander, not a victim of storms. The storm of divine wrath that falls on the wicked falls on him at the cross so it need not fall on those who are in him.</p>",
    "20": "<p>&apos;In the latter days you will understand it clearly.&apos; The prophetic word intelligible only after the fact. Luke 24:45: &apos;then he opened their minds so they could understand the Scriptures.&apos; The risen Jesus is the interpreter of the prophetic word — in the latter days, standing with the disciples after his resurrection, he makes the purposes of YHWH&apos;s heart clear. The disciples are the &apos;latter days&apos; generation to whom Jeremiah&apos;s prophecy finally becomes intelligible.</p>",
    "21": "<p>&apos;I did not send these prophets, yet they ran; I did not speak to them, yet they prophesied.&apos; The unsent, self-authorized prophets. Jesus: &apos;I was sent by him&apos; (<em>ekeinos me apesteilen</em>) — the &apos;sent-ness&apos; formula occurs dozens of times in John. His authority derives entirely from the one who sent him (John 8:42; 17:3, 8, 18, 21, 23, 25). The distinction between the authentic sent prophet and the self-running prophet is the distinction between Jesus and every false claimant.</p>",
    "22": "<p>&apos;If they had stood in my council and proclaimed my words, they would have turned them from their evil way.&apos; Authentic prophecy that comes from the divine council actually changes people. Jesus&apos;s words have transformative power: &apos;the words I have spoken to you are spirit and they are life&apos; (John 6:63); &apos;if you hold to my teaching, you are really my disciples. Then you will know the truth, and the truth will set you free&apos; (John 8:31-32). True prophetic words produce repentance and transformation; false ones confirm existing behavior.</p>",
    "23": "<p>&apos;Am I only a God nearby, declares the LORD, and not a God far away?&apos; The rhetorical question of divine omnipresence. Jesus promises the same omnipresence in his own person: &apos;I am with you always, to the very end of the age&apos; (Matt 28:20); &apos;where two or three gather in my name, there am I with them&apos; (Matt 18:20). The God who fills heaven and earth is now present &apos;nearby&apos; in the most intimate sense — in human flesh among his people.</p>",
    "24": "<p>&apos;Can anyone hide in secret places where I cannot see him? Do I not fill heaven and earth?&apos; The omniscient, omnipresent God who fills all space. Jesus speaks with the same authority about his own omniscience: &apos;he knew all people and needed no one to testify about man, for he himself knew what was in man&apos; (John 2:24-25); &apos;I am the good shepherd; I know my sheep&apos; (John 10:14). The God who fills heaven and earth has in Jesus &apos;filled&apos; earth in a new, incarnate way (Eph 4:10: &apos;he who descended is the very one who ascended higher than all the heavens, in order to fill the whole universe&apos;).</p>",
    "25": "<p>The dream-prophets claiming &apos;I have dreamed, I have dreamed!&apos; — the subjective, self-generated prophetic content. Jesus&apos;s contrast: &apos;I tell you what I have seen in the Father&apos;s presence&apos; (John 8:38); &apos;my Father has revealed this to you&apos; (Matt 16:17). The dreamed prophecy vs. the seen-and-revealed prophecy: Jesus&apos;s prophetic authority is grounded in direct, unmediated vision of the Father, not in the vagaries of the prophet&apos;s own dream-life.</p>",
    "26": "<p>&apos;How long shall there be lies in the heart of these prophets — prophesying the deceit of their own heart?&apos; The chronic condition of self-deception projected outward as prophecy. John 3:19-21: &apos;this is the verdict: light has come into the world, but people loved darkness instead of light because their deeds were evil.&apos; Jesus&apos;s light exposes the self-deceiving heart — not to condemn (John 3:17) but to bring into the light where transformation can occur.</p>",
    "27": "<p>The prophets making people forget YHWH&apos;s name through their dreams. The name-of-YHWH as the thing at risk. Jesus inverts this: he makes the Father&apos;s name known: &apos;I have revealed you to those whom you gave me&apos; (John 17:6); &apos;I have made you known to them, and will continue to make you known&apos; (John 17:26). The dream-prophets who cause forgetting of the divine name are countered by the Son who makes the Father permanently known.</p>",
    "28": "<p>&apos;What has straw to do with grain? Let the one who has my word speak it faithfully.&apos; The contrast between straw (the dream-prophet&apos;s chaff) and grain (YHWH&apos;s genuine word). John 6:35: &apos;I am the bread of life; whoever comes to me will never go hungry.&apos; Jesus is the grain — the nourishing, substantial word — versus the straw of false prophecy that fills but does not sustain. His word is the bread that gives life to the world (John 6:33).</p>",
    "29": "<p>&apos;Is not my word like fire, declares the LORD, and like a hammer that shatters rock?&apos; The divine word as fire and hammer. Heb 4:12: &apos;the word of God is alive and active, sharper than any double-edged sword, it penetrates even to dividing soul and spirit, joints and marrow; it judges the thoughts and attitudes of the heart.&apos; Jesus is the Word of God (John 1:1) — the fire, hammer, and sharp sword — who both shatters and reconstructs. At the transfiguration his face shines like the sun and his garments become brilliant (Matt 17:2) — the fire-of-YHWH incarnate.</p>",
    "30": "<p>&apos;I am against the prophets who steal my words from each other.&apos; Plagiarized prophecy — borrowed words passed off as direct revelation. Jesus&apos;s word is wholly his own and wholly the Father&apos;s: &apos;I did not speak on my own, but the Father who sent me commanded me to say all that I have spoken&apos; (John 12:49). There is no gap between his word and the Father&apos;s — no borrowing, no contamination, no secondhand transmission.</p>",
    "31": "<p>&apos;I am against the prophets who wag their own tongues and say: This is what the LORD declares.&apos; Tongue-wagging prophecy — the physical gesture of the false prophet speaking his own words with YHWH&apos;s authority. James 3:5-6: &apos;the tongue is a small part of the body, but it makes great boasts... it corrupts the whole body.&apos; Jesus&apos;s speech is purified of this gap: he speaks what he hears (John 8:26, 28, 40), sees (John 8:38), and receives (John 17:8).</p>",
    "32": "<p>&apos;I am against those who prophesy lying dreams ... who lead my people astray with reckless lies.&apos; The lying dreamers leading the flock astray. Jesus identifies himself as the only reliable leader of the flock: &apos;I am the gate for the sheep ... all who ever came before me were thieves and robbers&apos; (John 10:7-8). The lying prophets who lead astray are distinguished from the true shepherd by whether the flock is fed or fleeced, led or misled.</p>",
    "33": "<p>The <em>massa</em> (burden/oracle) wordplay: when the people ask &apos;What is the burden of the LORD?&apos; they become themselves the burden — &apos;you are the burden, and I will throw you off.&apos; Jesus&apos;s inversion: &apos;Come to me, all you who are weary and burdened, and I will give you rest. Take my yoke upon you... my yoke is easy and my burden is light&apos; (Matt 11:28-30). The <em>massa</em> that crushes becomes the light yoke that rests: the burden-language of Jer 23:33 is explicitly reversed in Jesus&apos;s invitation.</p>",
    "34": "<p>Punishment of anyone who says &apos;the burden of the LORD&apos; — prophet, priest, or person. The divine word has been so abused that the formula must be discontinued. Jesus announces a new covenant of speech: his words are his own because they are the Father&apos;s own — no formula required, because the speaker is himself the authentic mediator. His teaching &apos;as one who had authority, and not as their teachers of the law&apos; (Matt 7:29) bypasses the formula-dependence entirely.</p>",
    "35": "<p>The replacement formula: &apos;What has the LORD answered you?&apos; — asking about response rather than declaring a burden. Jesus models this responsive posture: &apos;the Son does nothing by himself; he can do only what he sees his Father doing&apos; (John 5:19). His whole prophetic ministry is one of listening for the Father&apos;s answer and declaring it. The disciple&apos;s prayer in John 17 shows this: Jesus reports what he has received and transmits it to his disciples.</p>",
    "36": "<p>&apos;You must no longer speak of the burden of the LORD, for the burden is every person&apos;s own word.&apos; The word has been so corrupted by misuse that the vocabulary itself must change. Jesus announces a new vocabulary: &apos;the words I have spoken to you are spirit and they are life&apos; (John 6:63); in him, YHWH&apos;s word and the speaker are identical — there is no gap between the formula and the reality. He himself is the Word (John 1:14).</p>",
    "37": "<p>The proper question to the prophet: &apos;What has the LORD answered you?&apos; The disciple&apos;s posture of asking rather than presuming. Jesus teaches his disciples to ask: &apos;ask and it will be given to you, seek and you will find, knock and the door will be opened to you&apos; (Matt 7:7); &apos;until now you have not asked for anything in my name; ask and you will receive, and your joy will be complete&apos; (John 16:24). The asking that replaces the false-burden formula.</p>",
    "38": "<p>Because they persist in using the forbidden formula despite the command — they will be punished. The persistence of self-willed religious speech after divine instruction is the same disobedience as the false prophecy itself. Jesus&apos;s warning: &apos;not everyone who says to me Lord, Lord will enter the kingdom of heaven, but only the one who does the will of my Father&apos; (Matt 7:21). Religious formula without covenant reality is the persistent sin Jeremiah identifies here.</p>",
    "39": "<p>&apos;I will surely lift you up and fling you away from my presence — you and the city I gave to your ancestors.&apos; The exile as rejection from the divine presence — the ultimate covenant curse. Jesus&apos;s most terrible words use the same expulsion language: &apos;then I will tell them plainly: I never knew you. Away from me, you evildoers!&apos; (Matt 7:23); &apos;depart from me, you who are cursed, into the eternal fire&apos; (Matt 25:41). The flung-away of 23:39 is the eternal consequence Jesus describes — and which he takes upon himself at the cross (&apos;My God, my God, why have you forsaken me?&apos;) so that his people never hear the final version.</p>",
    "40": "<p>&apos;And I will bring on you everlasting disgrace and lasting shame that will not be forgotten.&apos; Permanent disgrace — the opposite of covenant honor. Jesus&apos;s resurrection is the permanent reversal of this disgrace: &apos;looking to Jesus, the pioneer and perfecter of faith, who for the joy set before him endured the cross, scorning its shame, and sat down at the right hand of the throne of God&apos; (Heb 12:2). He endured the maximum disgrace and received the maximum honor — and in him those who were disgraced are restored to honor (1 Pet 2:6: &apos;the one who trusts in him will never be put to shame&apos;).</p>"
  },
  "24": {
    "1": "<p>The two baskets of figs before the temple: a vision given after Jehoiachin&apos;s deportation (597 BCE). The temple setting of the vision — figs placed before the LORD as offerings — makes the interpretation covenantal: YHWH is evaluating the quality of what is brought before him. Jesus&apos;s parable of the fig tree (Luke 13:6-9) and the cursed fig tree (Matt 21:18-22; Mark 11:12-14) both engage this fig-as-covenant-symbol tradition. The temple and the fig tree are interconnected in Jesus&apos;s final week.</p>",
    "2": "<p>Very good figs like first-ripe figs (<em>bikkurot</em>) — the highest quality, the first of the harvest, most prized — versus figs so rotten they cannot be eaten. The contrast is absolute: no middle ground, no &apos;acceptable but not great.&apos; Jesus&apos;s parable of the wheat and tares (Matt 13:24-30, 36-43) has the same structure: two categories, same apparent field, final sorting. The good figs represent the exiles YHWH is about to do good to; the bad figs those who remain in Jerusalem under Zedekiah.</p>",
    "3": "<p>YHWH asks Jeremiah what he sees. The prophetic dialogue method — YHWH invites the prophet&apos;s observation before giving the interpretation. Jesus frequently asks his disciples what they see or perceive (Matt 16:13-15: &apos;Who do people say the Son of Man is?&apos;; Matt 13:51: &apos;Have you understood all these things?&apos;). The Socratic method of prophetic pedagogy: the observation precedes the revelation.</p>",
    "4": "<p>The word of the LORD coming — the transition from observation to interpretation. Jesus&apos;s teaching moves between observation (looking at the birds, the lilies, the fig tree) and interpretation (the kingdom of God is like this). The rhythm of see-then-interpret is the educational method of the prophetic tradition into which Jesus inserts himself as the definitive teacher (Matt 7:28-29).</p>",
    "5": "<p>&apos;Like these good figs, I will look favorably on the exiles of Judah whom I sent away from this place to the land of the Babylonians.&apos; YHWH regards the exile as a divine sending for good, not merely a judgment. Jesus&apos;s understanding of his own &apos;sending&apos; into the world has the same logic: he is sent by the Father (John 3:17) for the good of those he goes to, not merely to condemn. The exiled people in Babylon, apparently abandoned, are being specially cared for.</p>",
    "6": "<p>&apos;I will keep my eyes on them for good, and I will bring them back to this land. I will build them and not tear down, plant them and not uproot.&apos; The four reversal pairs — build/tear down, plant/uproot — reverse the charter of Jer 1:10 (&apos;to tear down and to plant, to destroy and to build&apos;). Jesus&apos;s ministry is the new-covenant version: &apos;I will build my church, and the gates of Hades will not overcome it&apos; (Matt 16:18). The one who tears down the old structures builds the new one that cannot be pulled down.</p>",
    "7": "<p>&apos;I will give them a heart to know me, that I am the LORD. They will be my people and I will be their God, for they will return to me with all their heart.&apos; The proto-new-covenant verse of ch. 24: the <em>lev lada-at oti</em> (heart to know me) is the forerunner of Jer 31:33-34 (&apos;I will put my law in their minds and write it on their hearts... they will all know me&apos;). Jesus gives this heart through the Spirit: &apos;the Holy Spirit, whom the Father will send in my name, will teach you all things&apos; (John 14:26); &apos;they will all be taught by God&apos; (John 6:45 citing Isa 54:13). The heart-to-know-YHWH that exile could not produce, the Spirit provides through Christ.</p>",
    "8": "<p>&apos;But as for the bad figs ... Zedekiah king of Judah, his officials, the survivors in Jerusalem, and those who remain in Egypt.&apos; The category of those who did not go into exile, who resisted YHWH&apos;s purposes by staying. Jesus&apos;s warning: &apos;whoever finds their life will lose it, and whoever loses their life for my sake will find it&apos; (Matt 10:39). The counterintuitive reversal: those who held onto their position in Jerusalem (the &apos;good&apos; outcome) are the bad figs; those who lost everything to exile are the good figs. Surrender to YHWH&apos;s purposes, even painful ones, is the path of covenant.</p>",
    "9": "<p>The bad figs become a horror to all kingdoms — reproach, byword, taunt, curse everywhere YHWH drives them. The covenant-curse catalog (Deut 28:37: &apos;you will become a thing of horror, a byword and an object of ridicule among all the peoples where the LORD will drive you&apos;). Jesus bears all these titles at the cross (Matt 27:39-44: &apos;those who passed by hurled insults at him... the robbers who were crucified with him also heaped insults on him&apos;). He takes the position of the bad-fig curse upon himself so that those who trust him become the good figs — transformed.</p>",
    "10": "<p>&apos;And I will send the sword, famine, and pestilence against them until they are completely destroyed from the land.&apos; The triple judgment formula — sword, famine, pestilence — is the standard covenant-curse triad (Lev 26:25-26; Deut 28:22-25; Jer 14:12; 21:7). Jesus predicts the same triple judgment coming on Jerusalem in his generation (Matt 24:6-7: wars, famines, earthquakes as &apos;the beginning of birth pangs&apos;). The complete removal from the land is the ultimate covenant consequence — which he enters and absorbs so that a new community can be grafted in.</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'jeremiah')
    merge_comm(existing, JER_CHRIST)
    save_comm('mkt-christ', 'jeremiah', existing)

    out = json.loads((ROOT / 'data/commentary/mkt-christ/jeremiah.json').read_text())
    il  = json.loads((ROOT / 'data/interlinear/jeremiah.json').read_text())

    all_ok = True
    for ch in [22, 23, 24]:
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(out.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present')

if __name__ == '__main__':
    main()
